import{_ as t,o as n,c as i,a1 as a}from"./chunks/framework.BwbI10pK.js";const p=JSON.parse('{"title":"Testing Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"en/testing/index.md","filePath":"en/testing/index.md"}'),o={name:"en/testing/index.md"};function r(s,e,l,d,c,g){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="testing-engineering" tabindex="-1">Testing Engineering <a class="header-anchor" href="#testing-engineering" aria-label="Permalink to &quot;Testing Engineering&quot;">​</a></h1><blockquote><p>Subtitle: From load testing, end-to-end testing to unit testing, build a verifiable quality-assurance system.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>Testing is not a &quot;final step&quot; after development is done. It is an engineering method that runs through the full lifecycle of requirements, design, and delivery. This module decomposes testing into three goals: verification, isolation, and regression. Verify system boundaries under real pressure, isolate defects to specific layers, and ensure every change does not introduce new problems.</p><p>Each test category is accompanied by toolchain selection, scenario design, and result-analysis methods, avoiding pseudo-coverage where &quot;tests were run but no conclusion could be drawn.&quot;</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Load &amp; performance testing</strong>: Test plans, load models, JMeter script parameterization, TPS / response time / error-rate metrics, and bottleneck localization.</li><li><strong>End-to-end testing</strong>: Playwright / Cypress scenario design, assertion strategy, parallel execution, and stability governance.</li><li><strong>Unit &amp; integration testing</strong>: Jest / Vitest test pyramid, mock strategy, coverage boundaries, and contract testing.</li><li><strong>Monitoring &amp; observability</strong>: Grafana, APM, OCP metric collection, and 95th-percentile response-time analysis.</li><li><strong>Stability assurance</strong>: Degradation and circuit-breaker validation, capacity planning, and third-party dependency stress testing.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/testing/load-testing-practice">Load Testing Engineering Practice</a> — Full-process methodology for load testing and bottleneck diagnosis.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Testing engineers and quality owners who need to build a team-level load-testing and bottleneck-localization framework.</li><li>Intermediate and senior frontend engineers who want to understand system behavior under real pressure.</li><li>Frontend architects who need to evaluate scalability and fault tolerance during technical decision-making.</li></ul>',11)])])}const h=t(o,[["render",r]]);export{p as __pageData,h as default};
